```typescript
// tests/agents/[agent-name].test.ts
import { describe, it, expect, beforeEach } from '@jest/globals';
import { [AgentName]Agent } from '../../src/agents/[agent-name]';

describe('[AgentName] Agent', () => {
  let agent: [AgentName]Agent;

  beforeEach(() => {
    agent = new [AgentName]Agent();
  });

  describe('构造函数', () => {
    it('应该正确初始化 Agent', () => {
      expect(agent).toBeInstanceOf([AgentName]Agent);
    });

    it('应该设置正确的角色', () => {
      expect(agent['role']).toBe('期望的角色');
    });

    it('应该配置正确的工具', () => {
      expect(agent['allowedTools']).toContain('ExpectedTool');
    });
  });

  describe('getCapabilities()', () => {
    it('应该返回所有能力', () => {
      const capabilities = agent.getCapabilities();
      expect(capabilities).toContain('ExpectedCapability');
      expect(capabilities.length).toBeGreaterThan(0);
    });
  });

  describe('继承行为', () => {
    it('应该继承 BaseAgent 的权限模式', () => {
      expect(agent.getPermissionMode()).toBeDefined();
    });

    it('应该继承 BaseAgent 的思考模式', () => {
      agent.enableDeepThinking();
      expect(agent.getThinkingMode()).toBe('adaptive');
    });
  });
});
```

#### 预期成果
- ✅ 10 个新的测试文件
- ✅ 150+ 个新增测试用例
- ✅ Agent 覆盖率达到 80%+

